package generator

import (
	"encoding/json"

	"github.com/mykhaliev/agent-benchmark/model"
)

// TestIntent is one test as generated by the LLM.
// The LLM never emits YAML or recursive types — only this flat JSON object.
type TestIntent struct {
	Name          string            `json:"name"`
	Goal          string            `json:"goal"`
	SessionName   string            `json:"session_name"`
	Agent         string            `json:"agent,omitempty"`
	Prompt        string            `json:"prompt"`
	ExpectedTools []string          `json:"expected_tools,omitempty"`
	Checks        []Check           `json:"checks"`
	Extractors    []ExtractorIntent `json:"extractors,omitempty"`
	AllowedTools  []string          `json:"allowed_tools,omitempty"`
}

// Check is a flat assertion descriptor. anyOf/allOf/not are forbidden.
type Check struct {
	Type     string                     `json:"type"`
	Tool     string                     `json:"tool,omitempty"`
	Value    string                     `json:"value,omitempty"`
	Pattern  string                     `json:"pattern,omitempty"`
	Params   map[string]json.RawMessage `json:"params,omitempty"`
	Sequence []string                   `json:"sequence,omitempty"`
	Count    int                        `json:"count,omitempty"`
	Path     string                     `json:"path,omitempty"`
	Expected int                        `json:"expected,omitempty"`
}

// ExtractorIntent is a JSONPath extractor descriptor.
type ExtractorIntent struct {
	Tool         string `json:"tool"`
	Path         string `json:"path"`
	VariableName string `json:"variable_name"`
}

// BuildSessions converts []TestIntent into []model.Session, grouping tests by
// session_name in first-appearance order.
func BuildSessions(intents []TestIntent, _ map[string]string) []model.Session {
	sessionOrder := make([]string, 0)
	sessionMap := make(map[string]*model.Session)

	for _, intent := range intents {
		name := intent.SessionName
		if _, exists := sessionMap[name]; !exists {
			sessionOrder = append(sessionOrder, name)
			sess := &model.Session{Name: name}
			sessionMap[name] = sess
		}

		test := model.Test{
			Name:         intent.Name,
			Agent:        intent.Agent,
			Prompt:       intent.Prompt,
			AllowedTools: intent.AllowedTools,
		}

		for _, c := range intent.Checks {
			test.Assertions = append(test.Assertions, BuildAssertion(c))
		}

		for _, ex := range intent.Extractors {
			test.Extractors = append(test.Extractors, model.DataExtractor{
				ExtractorType: "jsonpath",
				Tool:          ex.Tool,
				Path:          ex.Path,
				VariableName:  ex.VariableName,
			})
		}

		sessionMap[name].Tests = append(sessionMap[name].Tests, test)
	}

	sessions := make([]model.Session, 0, len(sessionOrder))
	for _, name := range sessionOrder {
		sessions = append(sessions, *sessionMap[name])
	}
	return sessions
}

// BuildAssertion maps one Check to model.Assertion via direct field copy (no recursion).
func BuildAssertion(c Check) model.Assertion {
	params := make(map[string]string, len(c.Params))
	for k, raw := range c.Params {
		var s string
		if err := json.Unmarshal(raw, &s); err == nil {
			// Check if this string is itself a JSON object — flatten it.
			var nested map[string]interface{}
			if err := json.Unmarshal([]byte(s), &nested); err == nil {
				for subKey, subVal := range nested {
					switch v := subVal.(type) {
					case string:
						params[k+"."+subKey] = v
					default:
						b, _ := json.Marshal(v)
						params[k+"."+subKey] = string(b)
					}
				}
				continue
			}
			params[k] = s // plain string value
			continue
		}

		// If the value is a JSON object, flatten into dot-notation keys so
		// getNestedValue() can resolve them during assertion evaluation.
		var obj map[string]interface{}
		if err := json.Unmarshal(raw, &obj); err == nil {
			for subKey, subVal := range obj {
				switch v := subVal.(type) {
				case string:
					params[k+"."+subKey] = v
				default:
					b, _ := json.Marshal(v)
					params[k+"."+subKey] = string(b)
				}
			}
			continue
		}

		params[k] = string(raw) // bool/number/array/null → keep as-is
	}
	return model.Assertion{
		Type:     c.Type,
		Tool:     c.Tool,
		Value:    c.Value,
		Pattern:  c.Pattern,
		Params:   params,
		Sequence: c.Sequence,
		Count:    c.Count,
		Path:     c.Path,
		Expected: c.Expected,
	}
}
